const SPLASH = {"android/app/src/main/res/drawable-land-xxxhdpi/splash.png": "", "android/app/src/main/res/drawable-port-xhdpi/splash.png": "", "android/app/src/main/res/drawable-port-xxxhdpi/splash.png": "", "android/app/src/main/res/drawable-port-xxhdpi/splash.png": "", "android/app/src/main/res/drawable-land-hdpi/splash.png": "", "android/app/src/main/res/drawable-land-xhdpi/splash.png": "", "android/app/src/main/res/drawable-land-mdpi/splash.png": "", "android/app/src/main/res/drawable-land-xxhdpi/splash.png": "", "android/app/src/main/res/drawable-port-hdpi/splash.png": "", "android/app/src/main/res/drawable/splash.png": "", "android/app/src/main/res/drawable-port-mdpi/splash.png": ""};

const fs=require('fs');const path=require('path');let n=0;
for(const rel of Object.keys(SPLASH)){ if(!fs.existsSync(path.dirname(rel)))continue; fs.writeFileSync(rel,Buffer.from(SPLASH[rel],'base64')); n++; }
console.log('OK splash regenere : '+n+' fichiers (logo carre, centre)');
console.log('NATIF -> rebuild APK requis (Actions Build Native APK).');
